searchData={"items":[{"type":"module","title":"DropThe","doc":"Access open datasets for movies, series, crypto, companies from DropThe.\n\nHomepage: https://dropthe.org","ref":"DropThe.html"},{"type":"function","title":"DropThe.base_url/0","doc":"","ref":"DropThe.html#base_url/0"},{"type":"function","title":"DropThe.version/0","doc":"","ref":"DropThe.html#version/0"},{"type":"extras","title":"DropThe Elixir Client","doc":"# DropThe Elixir Client\n\nElixir client for the [DropThe](https://dropthe.org) open data API. Access datasets for movies, series, crypto, and companies.","ref":"readme.html"},{"type":"extras","title":"Installation - DropThe Elixir Client","doc":"Add `dropthe` to your list of dependencies in `mix.exs`:\n\n```elixir\ndef deps do\n  [\n    {:dropthe, \"~> 0.1.0\"}\n  ]\nend\n```","ref":"readme.html#installation"},{"type":"extras","title":"Usage - DropThe Elixir Client","doc":"```elixir\nDropThe.version()\n# => \"0.1.0\"\n\nDropThe.base_url()\n# => \"https://dropthe.org\"\n```","ref":"readme.html#usage"},{"type":"extras","title":"Links - DropThe Elixir Client","doc":"- [Homepage](https://dropthe.org)\n- [Documentation](https://dropthe.org/data/)\n- [GitHub](https://github.com/arnaudleroy-studio/dropthe-elixir)","ref":"readme.html#links"},{"type":"extras","title":"License - DropThe Elixir Client","doc":"MIT License. See [LICENSE](LICENSE) for details.","ref":"readme.html#license"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.40.1"}}